   158‚Üí
   159‚Üí      const shadows = await db.shadowSession.findMany();
   160‚Üí      const shadowMap = new Map(shadows.map((s) => [s.sessionId, s]));
   161‚Üí
   162‚Üí      const allIds = [...new Set([...cpMap.keys(), ...shadows.map((s) => s.sessionId)])];
