   512‚Üí  // ‚îÄ‚îÄ‚îÄ V2 helpers ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
   513‚Üí
   514‚Üí  type V2Session = {
   515‚Üí    summary: {
   516‚Üí      intent: string; outcome: string;
   517‚Üí      openItems: { id: number; text: string; status: string; subSessionId: string | null }[];
   518‚Üí      frictionItems: { text: string }[];
   519‚Üí      repoLearnings: { text: string }[];
   520‚Üí      codeLearnings: { path: string; finding: string }[];
   521‚Üí      workflowLearnings: { text: string }[];
   522‚Üí    } | null;
   523‚Üí  };
   524‚Üí
   525‚Üí  function mapV2Summary(summary: NonNullable<V2Session["summary"]>) {
   526‚Üí    return {
   527‚Üí      intent:            summary.intent,
   528‚Üí      outcome:           summary.outcome,
   529‚Üí      openItems:         summary.openItems.map((r) => ({ id: r.id, text: r.text, status: r.status, subSessionId: r.subSessionId })),
   530‚Üí      friction:          summary.frictionItems.map((r) => r.text),
   531‚Üí      repoLearnings:     summary.repoLearnings.map((r) => r.text),
   532‚Üí      codeLearnings:     summary.codeLearnings.map((r) => ({ path: r.path, finding: r.finding })),
   533‚Üí      workflowLearnings: summary.workflowLearnings.map((r) => r.text),
   534‚Üí    };
   535‚Üí  }
   536‚Üí
   537‚Üí  const V2_SESSION_INCLUDE = {
   538‚Üí    summary: {
   539‚Üí      include: {
   540‚Üí        openItems:         true,
   541‚Üí        frictionItems:     true,
   542‚Üí        repoLearnings:     true,
   543‚Üí        codeLearnings:     true,
   544‚Üí        workflowLearnings: true,
   545‚Üí      },
   546‚Üí    },
   547‚Üí  } as const;
   548‚Üí
   549‚Üí  const V2_SESSION_ORDER = { createdAt: "desc" as const };
   550‚Üí
   551‚Üí  // GET /api/v2/checkpoints
   552‚Üí  app.get("/api/v2/checkpoints", async (_req, res) => {
   553‚Üí    try {
   554‚Üí      const checkpoints = await db.checkpointMetadata.findMany({
   555‚Üí        include: {
   556‚Üí          tokenUsage: true,
   557‚Üí          filesTouched: { include: { filePath: true } },
   558‚Üí        },
   559‚Üí      });
   560‚Üí
   561‚Üí      const checkpointIds = checkpoints.map((c) => c.checkpointId);
   562‚Üí
   563‚Üí      const sessions = await db.checkpointSessionMetadata.findMany({
   564‚Üí        where:   { checkpointId: { in: checkpointIds } },
   565‚Üí        orderBy: V2_SESSION_ORDER,
   566‚Üí        include: V2_SESSION_INCLUDE,
   567‚Üí      });
   568‚Üí
   569‚Üí      // Group sessions by checkpointId
   570‚Üí      const sessionsByCheckpoint = new Map<string, typeof sessions>();
   571‚Üí      for (const s of sessions) {
   572‚Üí        const arr = sessionsByCheckpoint.get(s.checkpointId) ?? [];
   573‚Üí        arr.push(s);
   574‚Üí        sessionsByCheckpoint.set(s.checkpointId, arr);
   575‚Üí      }
   576‚Üí
   577‚Üí      res.json(checkpoints.map((c) => {
   578‚Üí        const cpSessions = sessionsByCheckpoint.get(c.checkpointId) ?? [];
   579‚Üí        const summary = cpSessions.find((s) => s.summary)?.summary ?? null;
   580‚Üí        const latestCreatedAt = cpSessions
   581‚Üí          .filter((s): s is typeof s & { createdAt: Date } => s.createdAt !== null)
   582‚Üí          .map((s) => s.createdAt)
   583‚Üí          .sort((a, b) => b.getTime() - a.getTime())[0] ?? null;
   584‚Üí        return {
   585‚Üí          id:               c.id,
   586‚Üí          checkpointId:     c.checkpointId,
   587‚Üí          cliVersion:       c.cliVersion,
   588‚Üí          strategy:         c.strategy,
   589‚Üí          branch:           c.branch,
   590‚Üí          checkpointsCount: c.checkpointsCount,
   591‚Üí          createdAt:        latestCreatedAt?.toISOString() ?? null,
   592‚Üí          tokenUsage: c.tokenUsage ? {
   593‚Üí            inputTokens:         c.tokenUsage.inputTokens,
   594‚Üí            cacheCreationTokens: c.tokenUsage.cacheCreationTokens,
   595‚Üí            cacheReadTokens:     c.tokenUsage.cacheReadTokens,
   596‚Üí            outputTokens:        c.tokenUsage.outputTokens,
   597‚Üí            apiCallCount:        c.tokenUsage.apiCallCount,
   598‚Üí          } : null,
   599‚Üí          filesTouched:  c.filesTouched.map((f) => f.filePath.path),
   600‚Üí          sessionCount:  cpSessions.length,
   601‚Üí          summary: summary ? mapV2Summary(summary) : null,
   602‚Üí        };
   603‚Üí      }));
   604‚Üí    } catch (err) {
   605‚Üí      res.status(500).json({ error: String(err) });
   606‚Üí    }
   607‚Üí  });
