   690‚Üí    const { status, subSessionId } = req.body as { status?: string; subSessionId?: string };
   691‚Üí    const allowed = ["open", "in_progress", "complete", "na"];
   692‚Üí    if (status !== undefined && !allowed.includes(status)) {
   693‚Üí      res.status(400).json({ error: "status must be open, in_progress, or complete" });
   694‚Üí      return;
   695‚Üí    }
   696‚Üí    try {
   697‚Üí      const updated = await db.openItem.update({
   698‚Üí        where: { id },
   699‚Üí        data: {
   700‚Üí          ...(status !== undefined ? { status } : {}),
   701‚Üí          ...(subSessionId !== undefined ? { subSessionId } : {}),
   702‚Üí        },
   703‚Üí      });
   704‚Üí      res.json({ id: updated.id, status: updated.status, subSessionId: updated.subSessionId });
   705‚Üí    } catch (err) {
   706‚Üí      res.status(500).json({ error: String(err) });
   707‚Üí    }
   708‚Üí  });
   709‚Üí
   710‚Üí  // POST /api/sessions/spawn
   711‚Üí  app.post("/api/sessions/spawn", async (req, res) => {
   712‚Üí    const { prompt, cwd, openItemIds, parentSessionId } = req.body as { prompt?: string; cwd?: string; openItemIds?: number[]; parentSessionId?: string };
   713‚Üí    if (!prompt || typeof prompt !== "string") {
   714‚Üí      res.status(400).json({ error: "prompt is required" });
   715‚Üí      return;
   716‚Üí    }
   717‚Üí    try {
   718‚Üí      const safeCwd = (cwd ?? process.env.HOME ?? "/tmp").replace(/'/g, "'\\''");
   719‚Üí      const safePrompt = prompt.replace(/'/g, "'\\''").replace(/\\/g, "\\\\").replace(/"/g, '\\"');
   720‚Üí      // Pass open item IDs and parent session so the SessionStart hook can link back
   721‚Üí      const envParts: string[] = [];
   722‚Üí      if (openItemIds?.length) envParts.push(`GOSSAMER_SPAWN_OPEN_ITEMS='${openItemIds.join(",")}'`);
   723‚Üí      if (parentSessionId) envParts.push(`GOSSAMER_SPAWN_PARENT_SESSION='${parentSessionId.replace(/'/g, "")}'`);
   724‚Üí      const envPrefix = envParts.length ? envParts.join(" ") + " " : "";
   725‚Üí      // Use AppleScript to open a new Terminal window running claude interactively
   726‚Üí      const script = [
   727‚Üí        `tell application "Terminal"`,
   728‚Üí        `  activate`,
   729‚Üí        `  do script "cd '${safeCwd}' && ${envPrefix}claude '${safePrompt}'"`,
   730‚Üí        `end tell`,
   731‚Üí      ].join("\n");
   732‚Üí      execSync(`osascript -e '${script.replace(/'/g, "'\\''")}'`);
   733‚Üí      // Mark selected open items as in_progress
   734‚Üí      if (openItemIds?.length) {
   735‚Üí        await db.openItem.updateMany({
   736‚Üí          where: { id: { in: openItemIds } },
   737‚Üí          data: { status: "in_progress" },
   738‚Üí        });
   739‚Üí      }
   740‚Üí      res.json({ started: true });
   741‚Üí    } catch (err) {
   742‚Üí      res.status(500).json({ error: String(err) });
   743‚Üí    }
   744‚Üí  });
   745‚Üí
   746‚Üí  // GET /api/search?q=TEXT[&limit=N]
   747‚Üí  app.get("/api/search", async (req, res) => {
   748‚Üí    const q     = typeof req.query.q     === "string" ? req.query.q.trim()         : "";
   749‚Üí    const limit = typeof req.query.limit === "string" ? parseInt(req.query.limit)  : 50;
   750‚Üí    if (!q) { res.status(400).json({ error: "q is required" }); return; }
   751‚Üí    try {
   752‚Üí      const results = await searchLogContent(db, q, Math.min(limit, 200));
   753‚Üí      res.json(results);
   754‚Üí    } catch (err) {
   755‚Üí      // FTS5 MATCH errors (bad syntax) come back as exceptions
   756‚Üí      res.status(400).json({ error: String(err) });
   757‚Üí    }
   758‚Üí  });
   759‚Üí
   760‚Üí  // Create HTTP server and attach WebSocket server (shared port)
   761‚Üí  const httpServer = createServer(app);
   762‚Üí  const wss = new WebSocketServer({ server: httpServer });
   763‚Üí
   764‚Üí  // WebSocket change detection ‚Äî poll every 2s, broadcast on new log events, checkpoints, or shadow sessions
   765‚Üí  let lastMaxLogEventId: number | null = null;
   766‚Üí  let lastMaxCheckpointId: number | null = null;
   767‚Üí  let lastMaxShadowSessionId: number | null = null;
   768‚Üí  const broadcast = () => {
   769‚Üí    const message = JSON.stringify({ type: "sessions_updated" });
   770‚Üí    for (const client of wss.clients) {
   771‚Üí      if (client.readyState === WebSocket.OPEN) {
   772‚Üí        client.send(message);
   773‚Üí      }
   774‚Üí    }
   775‚Üí  };
   776‚Üí  const poller = setInterval(async () => {
   777‚Üí    try {
   778‚Üí      const [latestLogEvent, latestCheckpoint, latestShadow] = await Promise.all([
   779‚Üí        db.logEvent.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
   780‚Üí        db.checkpointMetadata.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
   781‚Üí        db.shadowSession.findFirst({ orderBy: { id: "desc" }, select: { id: true } }),
   782‚Üí      ]);
   783‚Üí      const curLogEvent   = latestLogEvent?.id   ?? null;
   784‚Üí      const curCheckpoint = latestCheckpoint?.id ?? null;
   785‚Üí      const curShadow     = latestShadow?.id     ?? null;
   786‚Üí      if (curLogEvent !== lastMaxLogEventId || curCheckpoint !== lastMaxCheckpointId || curShadow !== lastMaxShadowSessionId) {
   787‚Üí        lastMaxLogEventId   = curLogEvent;
   788‚Üí        lastMaxCheckpointId = curCheckpoint;
   789‚Üí        lastMaxShadowSessionId = curShadow;
   790‚Üí        broadcast();
   791‚Üí      }
   792‚Üí    } catch {
   793‚Üí      // Non-fatal polling error ‚Äî keep running
   794‚Üí    }
   795‚Üí  }, 2000);
   796‚Üí
   797‚Üí  // ‚îÄ‚îÄ Checkpoint auto-indexer ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
   798‚Üí
   799‚Üí  const CHECKPOINT_BRANCH = "entire/checkpoints/v1";
   800‚Üí  let checkpointPoller: ReturnType<typeof setInterval> | null = null;
   801‚Üí
   802‚Üí  if (repoDir) {
   803‚Üí    const WORKTREE_PATH = join(repoDir, ".gossamer", "checkpoints");
   804‚Üí    mkdirSync(join(repoDir, ".gossamer"), { recursive: true });
   805‚Üí
   806‚Üí    // Ensure worktree exists (reuse across restarts)
   807‚Üí    if (!existsSync(WORKTREE_PATH)) {
   808‚Üí      try {
   809‚Üí        // Prune stale worktree registration first, then re-add
   810‚Üí        execSync(`git -C ${JSON.stringify(repoDir)} worktree prune`, { stdio: "pipe" });
   811‚Üí        execSync(
   812‚Üí          `git -C ${JSON.stringify(repoDir)} worktree add ${JSON.stringify(WORKTREE_PATH)} ${CHECKPOINT_BRANCH}`,
   813‚Üí          { stdio: "pipe" },
   814‚Üí        );
   815‚Üí        process.stderr.write(`checkpoint indexer: worktree created at ${WORKTREE_PATH}\n`);
   816‚Üí      } catch (err) {
   817‚Üí        process.stderr.write(`checkpoint indexer: failed to create worktree ‚Äî ${err}\n`);
   818‚Üí      }
   819‚Üí    }
   820‚Üí
   821‚Üí    const runIndex = async () => {
   822‚Üí      if (!existsSync(WORKTREE_PATH)) return;
   823‚Üí      try {
   824‚Üí        // Try to fetch from remote first (may fail if SSH unavailable ‚Äî non-fatal).
   825‚Üí        // Always reset to the local branch tip, which entire updates locally on commit.
   826‚Üí        try {
   827‚Üí          execSync(
   828‚Üí            `git -C ${JSON.stringify(WORKTREE_PATH)} fetch origin ${CHECKPOINT_BRANCH}`,
   829‚Üí            { stdio: "pipe" },
   830‚Üí          );
   831‚Üí        } catch { /* remote unavailable ‚Äî local commits still present */ }
   832‚Üí        execSync(
   833‚Üí          `git -C ${JSON.stringify(WORKTREE_PATH)} reset --hard ${CHECKPOINT_BRANCH}`,
   834‚Üí          { stdio: "pipe" },
   835‚Üí        );
   836‚Üí      } catch { /* non-fatal */ }
   837‚Üí      try {
   838‚Üí        const { checkpoints } = await indexAllCheckpointsV2(db, WORKTREE_PATH, undefined, repoDir);
   839‚Üí        if (checkpoints > 0) {
   840‚Üí          process.stderr.write(`checkpoint indexer: indexed ${checkpoints} checkpoints\n`);
   841‚Üí          broadcast();
   842‚Üí        }
   843‚Üí      } catch { /* non-fatal */ }
   844‚Üí    };
   845‚Üí
   846‚Üí    void runIndex();
   847‚Üí    checkpointPoller = setInterval(runIndex, 30_000);
   848‚Üí    process.stderr.write(`checkpoint indexer: polling every 30s (worktree: ${WORKTREE_PATH})\n`);
   849‚Üí  }
   850‚Üí
   851‚Üí  // ‚îÄ‚îÄ Shadow branch indexer ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ‚îÄ
   852‚Üí
   853‚Üí  let shadowPoller: ReturnType<typeof setInterval> | null = null;
   854‚Üí
   855‚Üí  if (repoDir) {
   856‚Üí    const runShadowIndex = async () => {
   857‚Üí      try {
   858‚Üí        const { sessions } = await indexAllShadowBranches(db, repoDir);
   859‚Üí        if (sessions > 0) broadcast();
   860‚Üí      } catch { /* non-fatal */ }
   861‚Üí    };
   862‚Üí
   863‚Üí    void runShadowIndex();
   864‚Üí    shadowPoller = setInterval(runShadowIndex, 5_000);
   865‚Üí    process.stderr.write(`shadow indexer: polling every 5s (repo: ${repoDir})\n`);
   866‚Üí  }
   867‚Üí
   868‚Üí  // Graceful shutdown
   869‚Üí  const shutdown = () => {
   870‚Üí    clearInterval(poller);
   871‚Üí    if (checkpointPoller) clearInterval(checkpointPoller);
   872‚Üí    if (shadowPoller) clearInterval(shadowPoller);
   873‚Üí    httpServer.close();
   874‚Üí    process.exit(0);
   875‚Üí  };
   876‚Üí  process.on("SIGINT", shutdown);
   877‚Üí  process.on("SIGTERM", shutdown);
   878‚Üí
   879‚Üí  await new Promise<void>((resolve) => {
   880‚Üí    httpServer.listen(port, () => {
   881‚Üí      process.stderr.write(`claude-hook-handler serve: listening on http://localhost:${port}\n`);
   882‚Üí      resolve();
   883‚Üí    });
   884‚Üí  });
   885‚Üí}
