app.get("/api/checkpoints/:id", async (req, res) => {
  try {
    const checkpoint = await db.checkpoint.findUnique({
      where: { checkpointId: req.params.id },
      include: {
        sessions: {
          include: { summary: true },
          orderBy: { sessionIndex: "asc" },
        },
      },
    });
