export interface LogContentSearchResult {
  logContentId: number;
  logEventId: number;
  sessionId: string;
  timestamp: string | null;
  contentType: string;
  toolName: string | null;
  /** "user" | "assistant" ‚Äî which side of the conversation this content came from. */
  logEventType: string;
  gitUserName: string | null;
  gitUserEmail: string | null;
  /** FTS5 snippet with ¬´match¬ª markers around matched terms. */
  snippet: string;
  /** BM25 rank (more negative = better match). */
  rank: number;
}

/**
 * Full-text search across LogContent fields (text, thinking, toolResultContent,
 * toolInput).  Accepts standard FTS5 MATCH syntax:
 *   - bare word:   foo
 *   - phrase:      "foo bar"
 *   - prefix:      foo*
 *   - column:      text:foo
 *   - boolean:     foo AND bar, foo OR bar, foo NOT bar
 *
 * Results are ordered by BM25 relevance (best first).
 */
export async function searchLogContent(
  db: PrismaClient,
  query: string,
  limit = 50,
): Promise<LogContentSearchResult[]> {
  type Row = {
    logContentId: number | bigint;
    logEventId: number | bigint;
    sessionId: string;
    timestamp: string | null;
    contentType: string;
    toolName: string | null;
    logEventType: string;
    gitUserName: string | null;
    gitUserEmail: string | null;
    snippet: string;
    rank: number;
  };

  // Run FTS match in a subquery first, then join for extra metadata.
  const rows = await db.$queryRawUnsafe<Row[]>(`
    SELECT
      fts.logContentId,
      fts.logEventId,
      fts.sessionId,
      fts.timestamp,
      fts.contentType,
      fts.toolName,
      fts.snippet,
      fts.rank,
      le.type   AS logEventType,
      s.gitUserName,
      s.gitUserEmail
    FROM (
      SELECT
        rowid                                              AS logContentId,
        logEventId,
        sessionId,
        timestamp,
        contentType,
        toolName,
        snippet(LogContentFts, -1, '¬´', '¬ª', '‚Ä¶', 24)   AS snippet,
        -- Weight text/thinking 10√ó higher than toolResultContent/toolInput.
        bm25(LogContentFts, 10, 10, 1, 1)                AS rank
      FROM LogContentFts
      WHERE LogContentFts MATCH ?
      ORDER BY rank
      LIMIT ?
    ) fts
    JOIN LogEvent le ON le.id = fts.logEventId
    LEFT JOIN Session s ON s.sessionId = fts.sessionId
  `, query, limit);

  return rows.map((r) => ({
    logContentId:  Number(r.logContentId),
    logEventId:    Number(r.logEventId),
    sessionId:     r.sessionId,
    timestamp:     r.timestamp,
    contentType:   r.contentType,
    toolName:      r.toolName || null,
    logEventType:  r.logEventType,
    gitUserName:   r.gitUserName || null,
    gitUserEmail:  r.gitUserEmail || null,
    snippet:       r.snippet,
    rank:          r.rank,
  }));
}

